============================================
   MODERN PIZZERIA DESIGN
   ============================================ */
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&family=Playfair+Display:wght@500;700&display=swap");

:root {
  --green: #23a455;
  --green-dark: #1a7c3a;
  --green-light: #e8f5f0;
  --accent: #ff6b35;
  --dark: #1a1a1a;
  --gray-dark: #404040;
  --gray: #6b7280;
  --gray-light: #f3f4f6;
  --cream: #fdfaf5;
  --border: #e5e7eb;

  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.08);
  --shadow-md: 0 8px 24px rgba(0, 0, 0, 0.12);
  --shadow-lg: 0 20px 40px rgba(0, 0, 0, 0.15);
  --shadow-xl: 0 25px 50px rgba(0, 0, 0, 0.2

   GLOBAL RESET & BASE STYLES
   ============================================ */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: 'Poppins', -apple-system, sans-serif;
  background: linear-gradient(135deg, #fdfaf5 0%, #f5f5f0 100%);
  color: var(--dark);
  line-height: 1.7;
  position: relative

rgba(255, 255, 255, 0.98);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(0, 0, 0, 0.05);
  position: sticky;
  top: 0;
  z-index: 1000;
  box-shadow: var(--shadow-sm);
}

.nav-container {
  max-width: 1400px;
  margin: 0 auto;
  padding: 1.2rem 2rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 2rem;
}

.logo img {
  height: 60px;
  width: auto;
  transition: transform 0.3s ease;
}

.logo img:hover {
  transform: scale(1.05);
}

.main-nav {
  list-style: none;
  display: flex;
  gap: 3rem;
  margin: 0;
  padding: 0;
  flex-wrap: wrap;
  align-items: center;
}

.main-nav li {
  position: relative;
}

.main-nav a {
  color: var(--dark);
  text-decoration: none;
  font-weight: 500;
  font-size: 0.95rem;
  padding: 0.5rem 0;
  display: block;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  letter-spacing: 0.3px;
}

.main-nav a::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 0;
  height: 2px;
  background: linear-gradient(90deg, var(--green), var(--accent));
  transition: width 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.main-nav a:hover {
  color: var(--green);
}

.main-nav a:hover::after {
  width: 100%;
}

.main-nav a.active {
  color: var(--green);
  font-weight: 700;
}

.main-nav a.active::after {
  width: 100%;
}

/* Dropdown Navigation */
.dropdown {
  position: relative;
}

.dropbtn {
  margin: 0;
}

.dropdown-content {
  display: none;
  position: absolute;
  top: calc(100% + 12px);
  left: 0;
  min-width: 220px;
  background: white;
  border: 1px solid var(--border);
  border-radius: 12px;
  box-shadow: var(--shadow-lg);
  padding: 0.8rem 0;
  z-index: 1001;
  list-style: none;
  animation: slideDown 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.dropdown-content a {
  display: block;
  padding: 0.9rem 1.5rem;
  color: var(--dark);
  text-decoration: none;
  font-size: 0.9rem;
  transition: all 0.2s ease;
  position: relative;
}

.dropdown-content a:hover {
  background: linear-gradient(90deg, rgba(35, 164, 85, 0.08), transparent);
  color: var(--green);
  padding-left: 1.8rem

linear-gradient(135deg, rgba(35, 164, 85, 0.1) 0%, rgba(255, 107, 53, 0.05) 100%),
    url("https://images.unsplash.com/photo-1628840042765-356cda0b3f83?w=1600&q=80") center/cover no-repeat;
  color: white;
  text-align: center;
  padding: 8rem 2rem 6rem;
  min-height: 65vh;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

#hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(26, 26, 26, 0.3) 0%, rgba(35, 164, 85, 0.4) 100%);
  z-index: 1;
}

.hero-content {
  background: linear-gradient(135deg, rgba(26, 122, 58, 0.95) 0%, rgba(35, 164, 85, 0.92) 100%);
  padding: 4rem 3rem;
  width: 100%;
  position: relative;
